// // This module implements a 4-bit DRAM cell with read and write capabilities. It has an input for data (4 bits), a read disable (RD), a write disable (WD), and an output for the stored data (4 bits). The cell should store data when WD is deasserted and provide the stored data on the output when RD is deasserted.
module dram_cell(clk, WE, RE, din, dout);  
    input clk;  
    input WE;  
    input RE;  
    input [3:0] din;  
    output reg [3:0] dout;  
    reg [3:0] storage;  

    always @(posedge clk) begin  
        if (WE) begin  
            storage <= din;  
        end  
        if (RE) begin  
            dout <= storage;  
        end  
    end  
endmodule
